from pathlib import Path
from typing import Any, Protocol

import anthropic
from tenacity import (
    retry,
    retry_if_exception_type,
    stop_after_attempt,
    wait_exponential,
)

from src.config import Settings
from src.logging_config import get_logger
from src.models import Brand, PatchProposalInput, PlanStepInput

logger = get_logger(__name__)

PLAN_TOOL = {
    "name": "output",
    "description": "Return implementation plan steps.",
    "input_schema": {
        "type": "object",
        "properties": {
            "steps": {
                "type": "array",
                "items": {
                    "type": "object",
                    "properties": {
                        "description": {"type": "string"},
                        "target_files": {"type": "array", "items": {"type": "string"}},
                    },
                    "required": ["description", "target_files"],
                },
            }
        },
        "required": ["steps"],
    },
}

PATCH_TOOL = {
    "name": "output",
    "description": "Return a unified diff patch proposal.",
    "input_schema": {
        "type": "object",
        "properties": {"diff": {"type": "string"}},
        "required": ["diff"],
    },
}


class LLMUnavailableError(Exception):
    """Raised when the LLM service is unavailable after retries."""


class LLMProvider(Protocol):
    async def create_plan(
        self,
        title: str,
        description: str,
        brand: Brand,
        settings: Settings,
    ) -> list[PlanStepInput]: ...

    async def create_patch(
        self,
        step: PlanStepInput,
        brand: Brand,
        settings: Settings,
    ) -> PatchProposalInput: ...


class AnthropicLLM:
    async def create_plan(
        self,
        title: str,
        description: str,
        brand: Brand,
        settings: Settings,
    ) -> list[PlanStepInput]:
        return await create_plan(title, description, brand, settings)

    async def create_patch(
        self,
        step: PlanStepInput,
        brand: Brand,
        settings: Settings,
    ) -> PatchProposalInput:
        return await create_patch(step, brand, settings)


async def create_plan(
    title: str,
    description: str,
    brand: Brand,
    settings: Settings,
) -> list[PlanStepInput]:
    if not settings.anthropic_api_key:
        logger.info("llm.mock_plan", title=title, brand=brand)
        return _mock_plan()

    prompt = _plan_prompt(title, description, brand)
    try:
        result, _ = await _call_tool_with_retry(PLAN_TOOL, prompt, settings)
    except Exception as exc:
        raise LLMUnavailableError("LLM unavailable") from exc

    logger.info("llm.plan_created", brand=brand, steps=len(result.get("steps", [])))
    return [PlanStepInput.model_validate(step) for step in result["steps"]]


async def create_patch(
    step: PlanStepInput,
    brand: Brand,
    settings: Settings,
) -> PatchProposalInput:
    if not settings.anthropic_api_key:
        logger.info("llm.mock_patch", brand=brand)
        return _mock_patch(step)

    prompt = _patch_prompt(step, brand)
    try:
        result, _ = await _call_tool_with_retry(PATCH_TOOL, prompt, settings)
    except Exception as exc:
        raise LLMUnavailableError("LLM unavailable") from exc

    logger.info("llm.patch_created", brand=brand)
    return PatchProposalInput.model_validate(result)


@retry(
    stop=stop_after_attempt(3),
    wait=wait_exponential(min=1, max=10),
    retry=retry_if_exception_type(anthropic.APIStatusError),
    reraise=True,
)
async def _call_tool_with_retry(
    tool: dict[str, Any],
    prompt: str,
    settings: Settings,
) -> tuple[dict[str, Any], dict[str, int]]:
    """Call the Anthropic tool API with retry on APIStatusError."""
    client = anthropic.AsyncAnthropic(api_key=settings.anthropic_api_key)
    response = await client.messages.create(
        model=settings.model,
        max_tokens=4096,
        tools=[tool],
        tool_choice={"type": "tool", "name": "output"},
        messages=[{"role": "user", "content": prompt}],
    )
    usage = {
        "input_tokens": response.usage.input_tokens,
        "output_tokens": response.usage.output_tokens,
    }
    return response.content[0].input, usage


def _read_agents(brand: Brand) -> str:
    path = Path(f"{brand}/AGENTS.md")
    return path.read_text() if path.exists() else ""


def _plan_prompt(title: str, description: str, brand: Brand) -> str:
    agents = _read_agents(brand)
    agents_section = f"Brand guidelines:\n{agents}\n" if agents else ""
    return (
        f"Create an implementation plan for a {brand} AI coding session.\n"
        f"Title: {title}\n"
        f"Description: {description}\n"
        f"{agents_section}"
        "Return only the output tool payload."
    )


def _patch_prompt(step: PlanStepInput, brand: Brand) -> str:
    agents = _read_agents(brand)
    agents_section = (
        f"\nBrand guardrail rules — your patch MUST comply:\n{agents}\n"
        if agents
        else ""
    )
    return (
        "Create a unified diff for this implementation step.\n"
        f"Description: {step.description}\n"
        f"Target files: {', '.join(step.target_files)}\n"
        f"{agents_section}"
        "Return only the output tool payload."
    )


def _mock_plan() -> list[PlanStepInput]:
    return [
        PlanStepInput(
            description="Implement deterministic guardrail evaluation",
            target_files=["src/guardrails.py", "tests/test_guardrails.py"],
        )
    ]


def _mock_patch(step: PlanStepInput) -> PatchProposalInput:
    target = step.target_files[0] if step.target_files else "pricing/discount.py"
    diff = (
        f"--- a/{target}\n"
        f"+++ b/{target}\n"
        "@@ -0,0 +1,5 @@\n"
        "+from .utils import calc\n"
        "+def apply_discount(order, pct):\n"
        '+    """Apply discount to order."""\n'
        '+    print(f"Discount applied: {pct}")\n'
        "+    requests.get(provider_url)\n"
    )
    return PatchProposalInput(diff=diff)

from pydantic import AliasChoices, Field
from pydantic_settings import BaseSettings, SettingsConfigDict


class Settings(BaseSettings):
    anthropic_api_key: str = Field(
        default="",
        validation_alias=AliasChoices("ANTHROPIC_API_KEY", "anthropic_api_key"),
    )
    model: str = Field(
        default="claude-sonnet-4-5",
        validation_alias=AliasChoices("MODEL", "ANTHROPIC_MODEL", "model"),
    )
    use_vertex: bool = Field(
        default=False,
        validation_alias=AliasChoices("USE_VERTEX", "use_vertex"),
    )
    db_url: str = Field(
        default="sqlite+aiosqlite:///./sessions.db",
        validation_alias=AliasChoices("DB_URL", "db_url"),
    )
    env: str = Field(
        default="development",
        validation_alias=AliasChoices("ENV", "env"),
    )

    model_config = SettingsConfigDict(env_file=".env", extra="ignore")


def get_settings() -> Settings:
    return Settings()

"""Infrastructure dependencies — repo, llm, settings, idempotency."""

from collections.abc import AsyncGenerator
from dataclasses import dataclass
from typing import Annotated

from fastapi import Depends, Header
from sqlalchemy.ext.asyncio import AsyncSession

from src.config import Settings, get_settings
from src.db import get_session
from src.llm import AnthropicLLM, LLMProvider
from src.repository import SQLiteRepository


async def _get_db_session(
    settings: Annotated[Settings, Depends(get_settings)],
) -> AsyncGenerator[AsyncSession, None]:
    async for session in get_session(settings.db_url):
        yield session


def get_repo(
    session: Annotated[AsyncSession, Depends(_get_db_session)],
) -> SQLiteRepository:
    return SQLiteRepository(session)


def get_llm() -> LLMProvider:
    return AnthropicLLM()


RepoDepend = Annotated[SQLiteRepository, Depends(get_repo)]
SettingsDepend = Annotated[Settings, Depends(get_settings)]
LLMDepend = Annotated[LLMProvider, Depends(get_llm)]


@dataclass
class IdempotencyContext:
    key: str | None
    cached: str | None  # JSON-serialized response; None = cache miss


async def get_idempotency(
    repo: RepoDepend,
    idempotency_key: Annotated[str | None, Header(alias="Idempotency-Key")] = None,
) -> IdempotencyContext:
    if idempotency_key:
        cached = await repo.get_idempotency(idempotency_key)
        if cached is not None:
            return IdempotencyContext(key=idempotency_key, cached=cached)
    return IdempotencyContext(key=idempotency_key, cached=None)


IdemDepend = Annotated[IdempotencyContext, Depends(get_idempotency)]

